fileContexts.content:
1	---
2	import "../styles/global.css";
3	import {
4	  BookOpen,
5	  ChevronDown,
6	  ChevronRight,
7	  Download,
8	  Github,
9	  List,
10	  Moon,
11	  PenLine,
12	  Rocket,
13	  Search,
14	  Sun,
15	  WandSparkles,
16	} from "lucide-astro";
17	
18	const {
19	  title = "Documentation",
20	  htmlLang = "zh-CN",
21	  locale = "zh",
22	  languageLabel = "中文",
23	  languageOptions = [
24	    { locale: "zh", label: "中文", href: "/" },
25	    { locale: "en", label: "English", href: "/en/" },
26	  ],
27	  navItems = ["Documentation", "Guides", "API reference", "Changelog"],
28	  sidebarGroups = [],
29	  expandableSidebarItems = [],
30	  sidebarChildren = {},
31	  sidebarLinks = {},
32	  tocTitle = "On this page",
33	  tocItems = [],
34	  ui = {
35	    searchLabel: "Search docs",
36	    searchPlaceholder: "Search...",
37	    downloadLabel: "Download",
38	    githubLabel: "GitHub repository",
39	    themeLabel: "Theme",
40	    starsFallback: "Stars",
41	  },
42	} = Astro.props;
43	
44	const homeHref = locale === "en" ? "/en/" : "/";
45	const sidebarIcons = {
46	  rocket: Rocket,
47	  book: BookOpen,
48	  wand: WandSparkles,
49	  pen: PenLine,
50	};
51	---
52	
53	<!doctype html>
54	<html lang={htmlLang}>
55	  <head>
56	    <meta charset="UTF-8" />
57	    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
58	    <meta
59	      name="description"
60	      content="Claude Code Router documentation site built with Astro."
61	    />
62	    <script is:inline>
63	      (() => {
64	        const storageKey = "ccr-docs-theme";
65	
66	        try {
67	          const storedTheme = localStorage.getItem(storageKey);
68	          const prefersDark = window.matchMedia("(prefers-color-scheme: dark)").matches;
69	          const theme = storedTheme === "light" || storedTheme === "dark"
70	            ? storedTheme
71	            : prefersDark
72	              ? "dark"
73	              : "light";
74	
75	          document.documentElement.dataset.theme = theme;
76	          document.documentElement.dataset.themeSource = storedTheme ? "user" : "system";
77	        } catch {
78	          const prefersDark = window.matchMedia("(prefers-color-scheme: dark)").matches;
79	          document.documentElement.dataset.theme = prefersDark ? "dark" : "light";
80	          document.documentElement.dataset.themeSource = "system";
81	        }
82	      })();
83	    </script>
84	    <link rel="icon" href="/favicon.svg" type="image/svg+xml" />
85	    {
86	      languageOptions.map((option) => (
87	        <link
88	          rel="alternate"
89	          hreflang={option.locale === "zh" ? "zh-CN" : "en"}
90	          href={option.href}
91	        />
92	      ))
93	    }
94	    <title>{title} | Claude Code Router Docs</title>
95	  </head>
96	  <body>
97	    <div class="shell">
98	      <header class="topbar">
99	        <a class="brand" href={homeHref} aria-label="Claude Code Router Docs">
100	          <img src="/logo.png" alt="" class="brand-logo" />
101	          <span>CCR docs</span>
102	        </a>
103	
104	        <details class="language-switcher">
105	          <summary>
106	            <span>{languageLabel}</span>
107	            <ChevronDown size={16} aria-hidden="true" />
108	          </summary>
109	          <div class="language-menu">
110	            {
111	              languageOptions.map((option) => (
112	                <a
113	                  class:list={{ active: option.locale === locale }}
114	                  href={option.href}
115	                  hreflang={option.locale === "zh" ? "zh-CN" : "en"}
116	                >
117	                  {option.label}
118	                </a>
119	              ))
120	            }
121	          </div>
122	        </details>
123	
124	        <nav class="main-nav" aria-label="Primary navigation">
125	          {
126	            navItems.map((item, index) => (
127	              <a class:list={["nav-link", { active: index === 0 }]} href="#">
128	                {item}
129	              </a>
130	            ))
131	          }
132	        </nav>
133	
134	        <div class="top-actions">
135	          <label class="search" aria-label={ui.searchLabel}>
136	            <Search size={18} aria-hidden="true" />
137	            <input type="search" placeholder={ui.searchPlaceholder} />
138	            <kbd>⌘K</kbd>
139	          </label>
140	          <a
141	            class="soft-button icon-link"
142	            href="https://github.com/musistudio/claude-code-router/releases"
143	            aria-label={ui.downloadLabel}
144	          >
145	            <Download size={18} aria-hidden="true" />
146	          </a>
147	          <a
148	            class="soft-button github-button hide-small"
149	            href="https://github.com/musistudio/claude-code-router"
150	            aria-label={ui.githubLabel}
151	          >
152	            <Github size={18} aria-hidden="true" />
153	            <strong id="github-stars" aria-label="GitHub stars">Stars</strong>
154	          </a>
155	          <button class="icon-button theme-toggle" type="button" aria-label={ui.themeLabel} data-theme-toggle>
156	            <span class="theme-icon theme-icon-sun" aria-hidden="true">
157	              <Sun size={19} />
158	            </span>
159	            <span class="theme-icon theme-icon-moon" aria-hidden="true">
160	              <Moon size={19} />
161	            </span>
162	          </button>
163	        </div>
164	      </header>
165	
166	      <div class="content-grid">
167	        <aside class="sidebar" aria-label="Documentation sidebar">
168	          <div class="sidebar-inner">
169	            {
170	              sidebarGroups.map((group) => {
171	                const GroupIcon = sidebarIcons[group.icon] ?? BookOpen;
172	
173	                return (
174	                  <section class="sidebar-group">
175	                    <h2>
176	                      <GroupIcon class="group-icon" size={16} aria-hidden="true" />
177	                      {group.label}
178	                    </h2>
179	                    <ul>
180	                      {group.items.map((item) => {
181	                        const childItems = sidebarChildren[item] ?? [];
182	                        const isExpandable = expandableSidebarItems.includes(item) && childItems.length > 0;
183	
184	                        return (
185	                          <li>
186	                            {isExpandable ? (
187	                              <details class="sidebar-details">
188	                                <summary class="sidebar-link" aria-expanded="false">
189	                                  <span>{item}</span>
190	                                  <ChevronRight size={16} aria-hidden="true" />
191	                                </summary>
192	                                <ul class="sidebar-children">
193	                                  {childItems.map((child) => (
194	                                    <li>
195	                                      <a class="sidebar-child-link" href={sidebarLinks[child] ?? "#"}>
196	                                        {child}
197	                                      </a>
198	                                    </li>
199	                                  ))}
200	                                </ul>
201	                              </details>
202	                            ) : (
203	                              <a
204	                                class:list={["sidebar-link", { active: group.active === item }]}
205	                                href={sidebarLinks[item] ?? "#"}
206	                              >
207	                                <span>{item}</span>
208	                              </a>
209	                            )}
210	                          </li>
211	                        );
212	                      })}
213	                    </ul>
214	                  </section>
215	                );
216	              })
217	            }
218	          </div>
219	        </aside>
220	
221	        <main class="doc-main">
222	          <slot />
223	        </main>
224	
225	        <aside class="toc" aria-label={tocTitle}>
226	          <div class="toc-card">
227	            <h2>
228	              <List size={18} aria-hidden="true" />
229	              {tocTitle}
230	            </h2>
231	            <nav>
232	              {
233	                tocItems.map((item, index) => (
234	                  <a
235	                    class:list={{ active: index === 0 }}
236	                    href={typeof item === "string" ? `#section-${index + 1}` : item.href}
237	                  >
238	                    {typeof item === "string" ? item : item.label}
239	                  </a>
240	                ))
241	              }
242	            </nav>
243	          </div>
244	        </aside>
245	      </div>
246	    </div>
247	
248	    <script define:vars={{ starsFallback: ui.starsFallback }}>
249	      const starBadge = document.querySelector("#github-stars");
250	
251	      const formatStars = (count) => {
252	        if (!Number.isFinite(count)) return starsFallback;
253	        if (count >= 1000) {
254	          const rounded = Math.round(count / 100) / 10;
255	          return `${rounded.toFixed(rounded % 1 === 0 ? 0 : 1)}k`;
256	        }
257	        return count.toLocaleString();
258	      };
259	
260	      fetch("https://api.github.com/repos/musistudio/claude-code-router", {
261	        headers: { Accept: "application/vnd.github+json" },
262	      })
263	        .then((response) => {
264	          if (!response.ok) throw new Error("GitHub request failed");
265	          return response.json();
266	        })
267	        .then((repo) => {
268	          if (starBadge) {
269	            starBadge.textContent = formatStars(repo.stargazers_count);
270	          }
271	        })
272	        .catch(() => {
273	          if (starBadge) {
274	            starBadge.textContent = starsFallback;
275	          }
276	        });
277	    </script>
278	    <script>
279	      const themeToggle = document.querySelector("[data-theme-toggle]");
280	      const themeStorageKey = "ccr-docs-theme";
281	      const themeMediaQuery = window.matchMedia("(prefers-color-scheme: dark)");
282	
283	      const getStoredTheme = () => {
284	        try {
285	          const storedTheme = localStorage.getItem(themeStorageKey);
286	          return storedTheme === "light" || storedTheme === "dark" ? storedTheme : null;
287	        } catch {
288	          return null;
289	        }
290	      };
291	
292	      const getSystemTheme = () => (themeMediaQuery.matches ? "dark" : "light");
293	
294	      const applyTheme = (theme, source = "system") => {
295	        const nextTheme = theme === "dark" ? "dark" : "light";
296	        document.documentElement.dataset.theme = nextTheme;
297	        document.documentElement.dataset.themeSource = source;
298	        document.documentElement.style.colorScheme = nextTheme;
299	
300	        if (themeToggle instanceof HTMLButtonElement) {
301	          themeToggle.setAttribute("aria-pressed", nextTheme === "dark" ? "true" : "false");
302	        }
303	      };
304	
305	      applyTheme(getStoredTheme() ?? getSystemTheme(), getStoredTheme() ? "user" : "system");
306	
307	      themeToggle?.addEventListener("click", () => {
308	        const currentTheme = document.documentElement.dataset.theme === "dark" ? "dark" : "light";
309	        const nextTheme = currentTheme === "dark" ? "light" : "dark";
310	
311	        try {
312	          localStorage.setItem(themeStorageKey, nextTheme);
313	        } catch {}
314	
315	        applyTheme(nextTheme, "user");
316	      });
317	
318	      themeMediaQuery.addEventListener("change", () => {
319	        if (!getStoredTheme()) {
320	          applyTheme(getSystemTheme(), "system");
321	        }
322	      });
323	
324	      const sidebarDetails = document.querySelectorAll(".sidebar-details");
325	      const reduceMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
326	
327	      sidebarDetails.forEach((details) => {
328	        const summary = details.querySelector("summary");
329	        const children = details.querySelector(".sidebar-children");
330	
331	        if (!(summary instanceof HTMLElement) || !(children instanceof HTMLElement)) {
332	          return;
333	        }
334	
335	        summary.setAttribute("aria-expanded", details.open ? "true" : "false");
336	
337	        summary.addEventListener("click", (event) => {
338	          event.preventDefault();
339	
340	          if (details.dataset.animating === "true") return;
341	
342	          const isOpen = details.open;
343	          details.dataset.animating = "true";
344	
345	          if (reduceMotion) {
346	            details.open = !isOpen;
347	            summary.setAttribute("aria-expanded", details.open ? "true" : "false");
348	            delete details.dataset.animating;
349	            return;
350	          }
351	
352	          if (isOpen) {
353	            children.style.height = `${children.scrollHeight}px`;
354	            children.getBoundingClientRect();
355	            details.classList.add("is-collapsing");
356	            summary.setAttribute("aria-expanded", "false");
357	
358	            window.requestAnimationFrame(() => {
359	              children.style.height = "0px";
360	            });
361	
362	            const finishClose = (transitionEvent) => {
363	              if (transitionEvent.propertyName !== "height") return;
364	              children.removeEventListener("transitionend", finishClose);
365	              details.open = false;
366	              details.classList.remove("is-collapsing");
367	              children.style.height = "";
368	              delete details.dataset.animating;
369	            };
370	
371	            children.addEventListener("transitionend", finishClose);
372	            return;
373	          }
374	
375	          details.open = true;
376	          summary.setAttribute("aria-expanded", "true");
377	          children.style.height = "0px";
378	          children.style.opacity = "0";
379	          children.getBoundingClientRect();
380	
381	          window.requestAnimationFrame(() => {
382	            children.style.height = `${children.scrollHeight}px`;
383	            children.style.opacity = "";
384	          });
385	
386	          const finishOpen = (transitionEvent) => {
387	            if (transitionEvent.propertyName !== "height") return;
388	            children.removeEventListener("transitionend", finishOpen);
389	            children.style.height = "";
390	            delete details.dataset.animating;
391	          };
392	
393	          children.addEventListener("transitionend", finishOpen);
394	        });
395	      });
396	    </script>
397	  </body>
398	</html>
